扫描线 经典应用，解决平面矩形覆盖的面积和问题。（也能够扩展到空间和其它图形）。 思想是水平或竖直方向扫描，以下以水平方向扫描为例，也就是矩形的竖边作为扫描线。从左往右扫，将整个图形分成若干个小矩形相加（如果上下两个矩形分开，视为合并在一起的就好）。那么，扫过的距离就是小矩形的宽，只有长在不断变化。使用线段树维护扫过区间内被覆盖的次数和长度，然后相乘即可。 具体思路如下：首先按照边来读入，对左边的边标记为1，右边的标记为-1，然后离散化，使用二分来查找对应的边。建立线段树，其中的每一个点表示一条线段，维护该线段的长度len与被多少个矩形覆盖的cnt。按照每一条边去更新线段树，每更新一条边在答案上累加。（扫描线）最后输出答案即可。 #include <cstdio> #include <algorithm> using namespace std; #define p1 (p<<1) #define p2 (p<<1|1) const int N=1e5+10; struct T { int l,r,cnt; double len; } t[N*8]; struct A { double x,y1,y2; int add; } a[N*2]; int n,len; double lsh[N*2]; bool cmp(A u,A v) {return u.x<v.x;} int val(double x) {return lower_bound(lsh+1,lsh+1+len,x)-lsh;} double raw(int x) {return lsh[x];} void pushUp(int p) {t[p].len=(t[p].cnt>0)?raw(t[p].r+1)-raw(t[p].l):t[p1].len+t[p2].len;} void build(int p,int l,int r) { t[p]={l,r,0,0}; if(l==r) return; int mid=(l+r)>>1; build(p1,l,mid),build(p2,mid+1,r); } void upd(int p,int l,int r,int add) { if(t[p].l>=l && t[p].r<=r) {t[p].cnt+=add,pushUp(p); return;} int mid=(t[p].l+t[p].r)>>1; if(l<=mid) upd(p1,l,r,add); if(r>mid) upd(p2,l,r,add); pushUp(p); } int main() { for(int tim=1;;tim++) { scanf("%d",&n); if(!n) break; printf("Test case #%d
",tim); for(int i=1;i<=n;i++) { double x1,y1,x2,y2; scanf("%lf%lf%lf%lf",&x1,&y1,&x2,&y2); a[i]={x1,y1,y2,1},a[i+n]={x2,y1,y2,-1}; lsh[i]=y1,lsh[i+n]=y2; } n*=2; sort(a+1,a+1+n,cmp),sort(lsh+1,lsh+1+n); len=unique(lsh+1,lsh+1+n)-lsh-1; build(1,1,len-1); double ans=0; upd(1,val(a[1].y1),val(a[1].y2)-1,a[1].add); for(int i=2;i<=n;i++) { ans+=t[1].len*(a[i].x-a[i-1].x); upd(1,val(a[i].y1),val(a[i].y2)-1,a[i].add); } printf("Total explored area: %.2lf

",ans); } return 0; }
